import socket
import json

# Game server configuration
SERVER_IP = '0.0.0.0'
SERVER_PORT = 12345
MAX_RESPONSE_SIZE = 65535

# Simulated game state and player list
game_state = {
    "status": "running",
    "players": [
        {"name": "Player1", "score": 100},
        {"name": "Player2", "score": 90}
    ]
}

def handle_status_query():
    return json.dumps(game_state, indent=4)

def main():
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    server_socket.bind((SERVER_IP, SERVER_PORT))
    
    print(f"Game Server listening on {SERVER_IP}:{SERVER_PORT}")
    
    while True:
        data, client_address = server_socket.recvfrom(MAX_RESPONSE_SIZE)
        query = data.decode('utf-8').strip().lower()
        
        if query == "status":
            response = handle_status_query()
            server_socket.sendto(response.encode('utf-8'), client_address)

if __name__ == "__main__":
    main()